from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about a monument (or related entity) into a single
    fluent sentence. All triples are combined into one coherent sentence.
    """
    if not triples:
        return ""

    # Group triples by subject
    from collections import defaultdict
    triples_by_subject: dict[str, list[Triple]] = defaultdict(list)
    for triple in triples:
        triples_by_subject[triple.subject].append(triple)

    # Identify the main subject (prefer monument-like subjects)
    main_subject = None
    for s in triples_by_subject.keys():
        if any(term in s.lower() for term in ["monument", "memorial", "plack", "battlefield", "park"]):
            main_subject = s
            break
    if main_subject is None:
        main_subject = triples[0].subject

    # Collect all information for the main subject
    all_clauses: list[str] = []
    location_info = {}  # Track location chain to avoid redundancy

    # First pass: process all triples for the main subject
    main_triples = triples_by_subject.get(main_subject, [])
    for triple in main_triples:
        p = triple.predicate
        o = triple.object.strip('"')

        if p == "category":
            all_clauses.append(f"is a {o}")
        elif p == "country":
            all_clauses.append(f"is in {o}")
            location_info["country"] = o
        elif p == "location":
            all_clauses.append(f"is located in {o}")
            location_info["location"] = o
        elif p == "municipality":
            all_clauses.append(f"municipality is {o}")
            location_info["municipality"] = o
        elif p == "state":
            all_clauses.append(f"state is {o}")
            location_info["state"] = o
        elif p == "district":
            all_clauses.append(f"district is {o}")
        elif p in ("established", "foundingDate"):
            if o and len(o) >= 10 and o[4] == '-' and o[7] == '-':
                try:
                    year, month, day = o[:4], o[5:7], o[8:10]
                    months = ["January", "February", "March", "April", "May", "June",
                              "July", "August", "September", "October", "November", "December"]
                    o = f"{months[int(month)-1]} {int(day)}, {year}"
                except:
                    pass
            all_clauses.append(f"was established on {o}")
        elif p in ("owner", "owningOrganisation"):
            all_clauses.append(f"is owned by {o}")
        elif p == "inaugurationDate":
            all_clauses.append(f"was inaugurated on {o}")
        elif p == "dedicatedTo":
            all_clauses.append(f"is dedicated to {o}")
        elif p == "designer":
            all_clauses.append(f"was designed by {o}")
        elif p == "material":
            all_clauses.append(f"is made of {o}")
        elif p == "nearestCity":
            all_clauses.append(f"is near {o}")
        elif p == "nativeName":
            all_clauses.append(f'native name is "{o}"')
        else:
            # Fallback for any unexpected predicate
            all_clauses.append(f"{p.replace('_', ' ')} {o}")

    # Build final sentence
    if all_clauses:
        if len(all_clauses) == 1:
            main_text = f"{main_subject} {all_clauses[0]}."
        else:
            main_text = f"{main_subject} " + ", ".join(all_clauses) + "."

        return main_text
    else:
        return f"{main_subject}."

# EVOLVE-BLOCK-END
